int score = 10;

score += 5;  // same as: score = score + 5;
score -= 2;  // same as: score = score - 2;
score *= 3;  // same as: score = score * 3;
score /= 2;  // same as: score = score / 2;

int a = 5;
int b = 8;

cout << (a == b) << endl; // 0 (false)
cout << (a < b) << endl;  // 1 (true)

bool isAdult = true;
bool hasTicket = false;

cout << (isAdult && hasTicket) << endl; // 0 (false — needs both)
cout << (isAdult || hasTicket) << endl; // 1 (true — needs at least one)
cout << (!hasTicket) << endl;           // 1 (true — flips false to true)

int count = 5;

count++; // same as: count = count + 1;
count--; // same as: count = count - 1;

#include <iostream>

using namespace std;

int main()
{
    int a = 5;
    int b = 5;

    cout << a++ << endl; // prints 5, THEN increments a to 6
    cout << ++b << endl; // increments b to 6 FIRST, then prints 6

    return 0;
}

